from adk import Agent
from adk.tools import Tool

class BiasAuditor(Tool):
    def __init__(self):
        self.protected_attrs = ['gender', 'race', 'age_group']
        self.baseline_rates = {}

    def measure_parity(self, agent_output, metadata):
        predictions = agent_output.get('decisions', [])
        attr_dists = {attr: {} for attr in self.protected_attrs}

        for pred, meta in zip(predictions, metadata):
            for attr in self.protected_attrs:
                group = meta.get(attr)
                if group:
                    attr_dists[attr].setdefault(group, []).append(pred['score'])

        disparities = {}
        for attr, groups in attr_dists.items():
            if len(groups) > 1:
                mean_scores = {g: np.mean(scores) for g, scores in groups.items()}
                max_diff = max(mean_scores.values()) - min(mean_scores.values())
                disparities[attr] = max_diff
        return disparities

from adk import Session

class DelegationBiasTracer:
    def __init__(self):
        self.bias_history = []

    def trace_delegation(self, session: Session, agent_id: str):
        state = session.get_state()
        bias_metrics = []

        for prev_agent in state['agent_history']:
            if 'fairness_score' in prev_agent:
                bias_metrics.append({
                    'agent': prev_agent['id'],
                    'score': prev_agent['fairness_score'],
                    'protected_group': prev_agent.get('group', 'unknown')
                })

        current_bias = self.compute_bias_gradient(bias_metrics)
        self.bias_history.append({
            'agent': agent_id,
            'delegation_bias': current_bias,
            'timestamp': session.timestamp
        })
        return current_bias > 0.1

from adk.tools import ToolResponse

class FairnessValidator:
    def __init__(self):
        self.proxy_features = ['zipcode', 'name_length', 'cultural_keywords']

    def validate_tool_response(self, response: ToolResponse):
        data = response.data
        correlations = {}

        for proxy in self.proxy_features:
            if proxy in data.columns:
                for protected in ['gender', 'race']:
                    if protected in data.columns:
                        corr = data[proxy].corr(data[protected])
                        correlations[f'{proxy}->{protected}'] = abs(corr)

        high_risk_proxies = [k for k, v in correlations.items() if v > 0.3]
        return {
            'is_fair': len(high_risk_proxies) == 0,
            'risky_proxies': high_risk_proxies,
            'correlation_scores': correlations
        }

